import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        byte[] buffer = new byte[10];
        int length = Math.min(name.length(), buffer.length);
        System.arraycopy(name.getBytes(), 0, buffer, 0, length);

        // Fill remaining bytes with zeros
        Arrays.fill(buffer, length, buffer.length, (byte) 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
